mapper.select:
SELECT stu.id AS id, cla.sid AS schoolYear, stu.img_url AS imgUrl, stu.chinese_name AS studentName, stu.gender AS gender, stu.student_no AS studentNo, stu.seat_no AS seatNo, cla.id AS classId, cla.class_name AS className, grade.grade_group_name AS gradeName, stu.status AS status, stu.english_name AS englishName, stu.education_no AS educationNo, stu.nationality AS nationality, stu.native_place AS nativePlace, stu.id_type AS idType, stu.id_no AS idNo, stu.permanent_address AS permanentAddress, stu.mobile_phone AS mobilePhone, stu.permanent_phone AS permanentPhone, sdr.out_time AS outTime, sdr.out_reason AS outReason, sdr.escalation_situation AS escalationSituation, stu.arts_science AS artsScience, cla.department AS department, stu.intention AS intention, stu.prove_img_url AS proveImgUrl FROM student_info stu LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN student_date_record sdr ON sdr.student_id = stu.id WHERE stu.deleted = 0
AND stu.school_id = #{reqModel.schoolId}
AND cla.sid = #{reqModel.schoolYear}
AND cla.grade_group = #{reqModel.gradeId}
AND cla.id = #{reqModel.classId}
AND (stu.chinese_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.english_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.student_no LIKE CONCAT('%', #{reqModel.studentInfo}, '%'))
AND stu.status = #{reqModel.status}
AND stu.gender = #{reqModel.gender}
AND stu.id_no = #{reqModel.idNo}
AND cla.department = #{reqModel.department}
AND stu.permanent_address LIKE CONCAT('%', #{reqModel.permanentAddress}, '%')
AND sdr.out_time >= CONCAT(#{reqModel.outYear}, '-01-01') AND sdr.out_time <= CONCAT(#{reqModel.outYear}, '-12-31')
AND cla.id IN
#{item}
ORDER BY stu.seat_no IS NULL, stu.seat_no ASC, stu.chinese_name ASC
